-- Generated by OrchestKit Claude Plugin
-- Created: 2026-05-22

PRAGMA user_version = 1;

CREATE TABLE IF NOT EXISTS sessions (
    sid              TEXT PRIMARY KEY,
    pid              INTEGER NOT NULL,
    cwd              TEXT NOT NULL,
    repo_hash        TEXT NOT NULL,
    repo_path        TEXT NOT NULL,
    worktree_path    TEXT,
    branch           TEXT,
    parent_sid       TEXT REFERENCES sessions(sid) ON DELETE SET NULL,
    status           TEXT NOT NULL DEFAULT 'running',
    started_at       INTEGER NOT NULL,
    last_heartbeat   INTEGER NOT NULL,
    ended_at         INTEGER,
    cc_version       TEXT,
    ork_version      TEXT
);

CREATE INDEX IF NOT EXISTS idx_sessions_repo ON sessions(repo_hash, status);
CREATE INDEX IF NOT EXISTS idx_sessions_heartbeat ON sessions(last_heartbeat);

CREATE TABLE IF NOT EXISTS locks (
    name             TEXT PRIMARY KEY,
    holder_sid       TEXT NOT NULL REFERENCES sessions(sid) ON DELETE CASCADE,
    acquired_at      INTEGER NOT NULL,
    expires_at       INTEGER NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_locks_expires ON locks(expires_at);

CREATE TABLE IF NOT EXISTS settings_overrides (
    sid              TEXT NOT NULL REFERENCES sessions(sid) ON DELETE CASCADE,
    key              TEXT NOT NULL,
    value            TEXT NOT NULL,
    set_at           INTEGER NOT NULL,
    PRIMARY KEY (sid, key)
);

CREATE TABLE IF NOT EXISTS worktree_links (
    child_sid        TEXT PRIMARY KEY REFERENCES sessions(sid) ON DELETE CASCADE,
    parent_sid       TEXT NOT NULL REFERENCES sessions(sid) ON DELETE CASCADE,
    purpose          TEXT,
    created_at       INTEGER NOT NULL,
    result_status    TEXT,
    result_payload   TEXT
);

CREATE INDEX IF NOT EXISTS idx_worktree_parent ON worktree_links(parent_sid);
